// ─────────────────────────────────────────────────────────
// NODO: Gestionar Sesion
// Extrae datos del mensaje entrante de Twilio WhatsApp
// y recupera o crea la sesion del cliente.
// ─────────────────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

const from    = body.From || body.from || '';
const msgBody = (body.Body || body.body || '').trim();
const phone   = from.replace('whatsapp:', '').replace('+', '');

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

// Palabras que reinician la conversacion desde cero
const resetWords = ['hola', 'hello', 'hi', 'inicio', 'menu', 'start', 'comenzar', 'reiniciar'];
const isReset = resetWords.includes(msgBody.toLowerCase());

if (isReset || !staticData.sessions[phone]) {
  staticData.sessions[phone] = {
    phone:          phone,
    from:           from,
    step:           'inicio',
    nombre:         '',
    localidad:      '',
    menu_opcion:    '',
    submenu_opcion: '',
    timestamp:      new Date().toISOString()
  };
}

const session = staticData.sessions[phone];
session.last_message = msgBody;
session.last_active  = new Date().toISOString();
staticData.sessions[phone] = session;

return [{ json: { ...session, incoming_msg: msgBody, phone, from } }];

// ─────────────────────────────────────────────────────────
// NODO: Procesar Mensaje
// Evalua el paso actual de la sesion y genera
// la respuesta correspondiente al cliente.
//
// PERSONALIZAR:
//   - Textos de los mensajes (variable 'reply')
//   - Opciones de los menus (objeto 'opciones')
//   - Subcategorias (objeto 'submenus')
// ─────────────────────────────────────────────────────────

const staticData = $getWorkflowStaticData('global');
const data    = $input.first().json;
const phone   = data.phone;
const msg     = data.incoming_msg.trim();
const session = staticData.sessions[phone];

let reply  = '';
let guardar = false;

// ── PASO 1: INICIO ──────────────────────────────────────
if (session.step === 'inicio') {
  session.step = 'esperando_nombre';
  reply =
    `👋 ¡Hola! Bienvenido/a a *[NOMBRE DE TU EMPRESA]* 🌞\n\n` +
    `[DESCRIPCION CORTA DE LA EMPRESA]\n\n` +
    `Para comenzar, ¿podrías decirme tu *nombre completo*?`;

// ── PASO 2: NOMBRE ──────────────────────────────────────
} else if (session.step === 'esperando_nombre') {
  session.nombre = msg;
  session.step   = 'esperando_localidad';
  reply = `Gracias, *${msg}* 😊\n\n¿En qué *localidad* o dirección estás ubicado/a?`;

// ── PASO 3: LOCALIDAD ───────────────────────────────────
} else if (session.step === 'esperando_localidad') {
  session.localidad = msg;
  session.step      = 'menu_principal';
  reply =
    `Perfecto, *${session.nombre}* de *${msg}* 📍\n\n` +
    `¿En qué podemos ayudarte hoy?\n\n` +
    `1️⃣ *[OPCION 1]*\n` +
    `2️⃣ *[OPCION 2]*\n` +
    `3️⃣ *[OPCION 3]*\n` +
    `4️⃣ *[OPCION 4]*\n` +
    `5️⃣ *Hablar con un asesor*\n\n` +
    `Respondé con el número de tu opción.`;

// ── PASO 4: MENU PRINCIPAL ──────────────────────────────
} else if (session.step === 'menu_principal') {

  // PERSONALIZAR: Reemplazar nombres y submenus segun tu negocio
  const opciones = {
    '1': {
      nombre:  '[OPCION 1]',
      submenu: '1️⃣ [Sub-opcion 1.1]\n2️⃣ [Sub-opcion 1.2]\n3️⃣ [Sub-opcion 1.3]\n4️⃣ [Sub-opcion 1.4]\n5️⃣ [Sub-opcion 1.5]'
    },
    '2': {
      nombre:  '[OPCION 2]',
      submenu: '1️⃣ [Sub-opcion 2.1]\n2️⃣ [Sub-opcion 2.2]\n3️⃣ [Sub-opcion 2.3]\n4️⃣ [Sub-opcion 2.4]\n5️⃣ [Sub-opcion 2.5]'
    },
    '3': {
      nombre:  '[OPCION 3]',
      submenu: '1️⃣ [Sub-opcion 3.1]\n2️⃣ [Sub-opcion 3.2]\n3️⃣ [Sub-opcion 3.3]\n4️⃣ [Sub-opcion 3.4]\n5️⃣ [Sub-opcion 3.5]'
    },
    '4': {
      nombre:  '[OPCION 4]',
      submenu: '1️⃣ [Sub-opcion 4.1]\n2️⃣ [Sub-opcion 4.2]\n3️⃣ [Sub-opcion 4.3]\n4️⃣ [Sub-opcion 4.4]\n5️⃣ [Sub-opcion 4.5]'
    },
    '5': { nombre: 'Asesor Humano', submenu: '' }
  };

  if (opciones[msg]) {
    session.menu_opcion = opciones[msg].nombre;
    if (msg === '5') {
      session.step = 'derivado';
      reply =
        `👤 Te paso el contacto de nuestro asesor:\n\n` +
        `📱 WhatsApp: [NUMERO_ASESOR]\n` +
        `👨‍💼 [NOMBRE_ASESOR]\n` +
        `🕐 [HORARIO_ATENCION]\n\n` +
        `¡Ya fue notificado y te contactará a la brevedad!`;
    } else {
      session.step = 'submenu';
      reply = `*${opciones[msg].nombre}*\n\n${opciones[msg].submenu}\n\nRespondé con el número.`;
    }
  } else {
    reply =
      `⚠️ Opción no válida. Respondé con un número del *1 al 5*:\n\n` +
      `1️⃣ [OPCION 1]\n2️⃣ [OPCION 2]\n3️⃣ [OPCION 3]\n4️⃣ [OPCION 4]\n5️⃣ Hablar con un asesor`;
  }

// ── PASO 5: SUBMENU ─────────────────────────────────────
} else if (session.step === 'submenu') {

  // PERSONALIZAR: Coincidir exactamente con los nombres del menu principal
  const submenus = {
    '[OPCION 1]': ['[Sub-opcion 1.1]', '[Sub-opcion 1.2]', '[Sub-opcion 1.3]', '[Sub-opcion 1.4]', '[Sub-opcion 1.5]'],
    '[OPCION 2]': ['[Sub-opcion 2.1]', '[Sub-opcion 2.2]', '[Sub-opcion 2.3]', '[Sub-opcion 2.4]', '[Sub-opcion 2.5]'],
    '[OPCION 3]': ['[Sub-opcion 3.1]', '[Sub-opcion 3.2]', '[Sub-opcion 3.3]', '[Sub-opcion 3.4]', '[Sub-opcion 3.5]'],
    '[OPCION 4]': ['[Sub-opcion 4.1]', '[Sub-opcion 4.2]', '[Sub-opcion 4.3]', '[Sub-opcion 4.4]', '[Sub-opcion 4.5]'],
  };

  const listaOpciones = submenus[session.menu_opcion] || [];
  const idx = parseInt(msg) - 1;

  if (idx >= 0 && idx < listaOpciones.length) {
    session.submenu_opcion = listaOpciones[idx];
    session.step           = 'finalizado';
    guardar                = true;
    reply =
      `✅ *Consulta registrada*\n\n` +
      `📋 Resumen:\n` +
      `• Nombre: *${session.nombre}*\n` +
      `• Localidad: *${session.localidad}*\n` +
      `• Tema: *${session.menu_opcion}*\n` +
      `• Detalle: *${session.submenu_opcion}*\n\n` +
      `Un asesor se comunicará a la brevedad. ¿Necesitás algo más?\n\n` +
      `1️⃣ Volver al menú\n2️⃣ Hablar con un asesor\n3️⃣ No, gracias`;
  } else {
    reply = `⚠️ Opción no válida. Respondé con un número del *1 al 5*.`;
  }

// ── PASO 6: FINALIZADO ──────────────────────────────────
} else if (session.step === 'finalizado') {
  if (msg === '1') {
    session.step = 'menu_principal';
    reply =
      `📋 *Menú principal:*\n\n` +
      `1️⃣ [OPCION 1]\n2️⃣ [OPCION 2]\n3️⃣ [OPCION 3]\n4️⃣ [OPCION 4]\n5️⃣ Hablar con un asesor`;
  } else if (msg === '2') {
    session.step = 'derivado';
    reply =
      `👤 Te paso el contacto de nuestro asesor:\n\n` +
      `📱 WhatsApp: [NUMERO_ASESOR]\n` +
      `👨‍💼 [NOMBRE_ASESOR]\n` +
      `🕐 [HORARIO_ATENCION]`;
  } else {
    reply        = `¡Gracias por contactarnos! 😊 Hasta pronto.`;
    session.step = 'inicio';
  }

// ── FALLBACK ─────────────────────────────────────────────
} else {
  session.step = 'inicio';
  reply =
    `👋 ¡Hola! Bienvenido/a a *[NOMBRE DE TU EMPRESA]*\n\n` +
    `¿Podrías decirme tu *nombre completo*?`;
}

staticData.sessions[phone] = session;

return [{ json: { ...data, reply, guardar, session_data: session } }];

// ─────────────────────────────────────────────────────────
// NODO: Preparar Datos
// Arma el objeto con los datos a guardar en
// Google Sheets y Excel.
// ─────────────────────────────────────────────────────────

const session = $json.session_data;
const now     = new Date();

return [{
  json: {
    fecha:            now.toLocaleDateString('es-AR'),
    hora:             now.toLocaleTimeString('es-AR'),
    nombre:           session.nombre           || '',
    telefono:         session.from             || '',
    localidad:        session.localidad        || '',
    categoria:        session.menu_opcion      || '',
    consulta_detalle: session.submenu_opcion   || '',
    resumen:          `${session.nombre} de ${session.localidad} consulto sobre ${session.menu_opcion} - ${session.submenu_opcion}`,
    estado:           'Pendiente',
    reply:            $json.reply
  }
}];

// ─────────────────────────────────────────────────────────
// NODO: Preparar Respuesta Twilio
// Arma el objeto con To, From y Body para
// enviar la respuesta al cliente via Twilio API.
//
// CONFIGURAR:
//   - From: reemplazar con tu numero Twilio real en produccion
//     Sandbox:   whatsapp:+14155238886
//     Produccion: whatsapp:+549XXXXXXXXXX
// ─────────────────────────────────────────────────────────

const session = $('Gestionar Sesion').first().json;
const data    = $input.first().json;

let to = session.from || data.from || '';

// Garantizar formato correcto: whatsapp:+XXXXXXXXXXX
if (to && !to.startsWith('whatsapp:')) {
  to = 'whatsapp:+' + to.replace(/\D/g, '');
}

const reply = data.reply || 'Gracias por contactarnos.';

return [{
  json: {
    To:   to,
    From: 'whatsapp:+14155238886',
    Body: reply
  }
}];
